const raw = ($json.tool_input && typeof $json.tool_input === 'object') ? $json.tool_input : $json;
const buttonId = String(raw.button_id || '').trim();
let action = String(raw.action || '').trim();
let jobId = String(raw.job_id || '').trim();
if (!action && buttonId.startsWith('owner_bulk_apply__')) action = 'apply';
if (!action && buttonId.startsWith('owner_bulk_cancel__')) action = 'cancel';
if (!jobId && buttonId.startsWith('owner_bulk_apply__')) jobId = buttonId.replace('owner_bulk_apply__', '');
if (!jobId && buttonId.startsWith('owner_bulk_cancel__')) jobId = buttonId.replace('owner_bulk_cancel__', '');
return [{
  json: {
    ...raw,
    action,
    job_id: jobId,
    chat_id: String(raw.chat_id || ''),
    test_mode: raw.test_mode === true,
  },
}];

const d = $('Normalize Apply Input').first().json || {};
const s = $('Inspect Inventory Schema').first().json || {};
const esc = (value) => String(value === undefined || value === null ? '' : value).replace(/'/g, "''");
const b = (value) => value === true || value === 'true' || value === 't' || value === 1 || value === '1';
const hasStoreId = b(s.has_store_id);
const hasSku = b(s.has_sku);
const hasUnit = b(s.has_unit);
const hasCategory = b(s.has_category);
const hasBrand = b(s.has_brand);
const hasIsActive = b(s.has_is_active);
const hasCreatedAt = b(s.has_created_at);
const hasUpdatedAt = b(s.has_updated_at);

const ensureSql = [
  'CREATE TABLE IF NOT EXISTS public.owner_import_jobs (job_id TEXT PRIMARY KEY, store_id BIGINT, chat_id TEXT NOT NULL, source_type TEXT, status TEXT NOT NULL, parsed_rows_json JSONB DEFAULT \'[]\'::jsonb, invalid_rows_json JSONB DEFAULT \'[]\'::jsonb, file_name TEXT, mime_type TEXT, created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW());',
  'ALTER TABLE public.owner_import_jobs ADD COLUMN IF NOT EXISTS source_ref TEXT;',
  'ALTER TABLE public.owner_import_jobs ADD COLUMN IF NOT EXISTS mode TEXT;',
  'ALTER TABLE public.owner_import_jobs ADD COLUMN IF NOT EXISTS total_rows INTEGER DEFAULT 0;',
  'ALTER TABLE public.owner_import_jobs ADD COLUMN IF NOT EXISTS valid_rows INTEGER DEFAULT 0;',
  'ALTER TABLE public.owner_import_jobs ADD COLUMN IF NOT EXISTS invalid_rows INTEGER DEFAULT 0;',
  'ALTER TABLE public.owner_import_jobs ADD COLUMN IF NOT EXISTS ambiguous_rows INTEGER DEFAULT 0;',
  'ALTER TABLE public.owner_import_jobs ADD COLUMN IF NOT EXISTS matched_rows INTEGER DEFAULT 0;',
  'ALTER TABLE public.owner_import_jobs ADD COLUMN IF NOT EXISTS new_rows INTEGER DEFAULT 0;',
  'ALTER TABLE public.owner_import_jobs ADD COLUMN IF NOT EXISTS applied_rows INTEGER DEFAULT 0;',
  'ALTER TABLE public.owner_import_jobs ADD COLUMN IF NOT EXISTS failed_rows INTEGER DEFAULT 0;',
  'ALTER TABLE public.owner_import_jobs ADD COLUMN IF NOT EXISTS report_manifest_json JSONB DEFAULT \'{}\'::jsonb;',
  'ALTER TABLE public.owner_import_jobs ADD COLUMN IF NOT EXISTS report_token TEXT;',
  'ALTER TABLE public.owner_import_jobs ADD COLUMN IF NOT EXISTS started_at TIMESTAMPTZ;',
  'ALTER TABLE public.owner_import_jobs ADD COLUMN IF NOT EXISTS finished_at TIMESTAMPTZ;',
  'CREATE TABLE IF NOT EXISTS public.owner_import_job_rows (job_id TEXT NOT NULL, row_no INTEGER NOT NULL, chunk_no INTEGER NOT NULL, raw_payload_json JSONB DEFAULT \'{}\'::jsonb, normalized_payload_json JSONB DEFAULT \'{}\'::jsonb, match_status TEXT NOT NULL, target_inventory_id BIGINT, target_sku TEXT, target_item_name TEXT, error_reason TEXT, review_reason TEXT, row_hash TEXT, apply_status TEXT DEFAULT \'pending\', created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW(), PRIMARY KEY (job_id, row_no));',
  "CREATE TABLE IF NOT EXISTS public.owner_operation_sessions (session_id TEXT PRIMARY KEY, store_id BIGINT, chat_id TEXT NOT NULL, operation_type TEXT NOT NULL, source_type TEXT NOT NULL, parsed_payload_json JSONB DEFAULT '{}'::jsonb, cleanup_summary_json JSONB DEFAULT '{}'::jsonb, preview_rows_json JSONB DEFAULT '[]'::jsonb, status TEXT NOT NULL, created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW());",
].join('\n');

if (!d.job_id) {
