    "  UPDATE public.owner_operation_sessions SET status = 'cancelled', updated_at = NOW() WHERE session_id = 'bulk_" + esc(d.job_id) + "' RETURNING session_id",
    ')',
    "SELECT CASE WHEN EXISTS (SELECT 1 FROM updated) THEN 'cancelled' ELSE 'job_missing' END AS result, '{}'::jsonb AS summary_json, COALESCE((SELECT report_manifest_json FROM updated LIMIT 1), '{}'::jsonb) AS report_manifest_json, '' AS message;",
  ].join('\n');
  return [{ json: { ...d, sql } }];
