if (row.result === 'cancelled') {
  return [{ json: makeButtons(
    'Bulk import cancelled. No catalog rows were applied.',
    [
      { id: 'owner_catalog_import', title: 'Upload Corrected File' },
      { id: 'owner_catalog_manual', title: 'Add items manually' },
      { id: 'owner_catalog_discount', title: 'Create discount' },
    ],
  ) }];
}
if (row.result === 'applied') {
  const lines = [
    'Bulk import applied.',
    'Applied rows: ' + Number(summary.applied_rows || 0),
    'Ambiguous rows left out: ' + Number(summary.ambiguous_rows || 0),
    'Invalid rows left out: ' + Number(summary.invalid_rows || 0),
  ];
  if (reportManifest.applied_url) lines.push('', 'Applied report: ' + reportManifest.applied_url);
  return [{ json: makeButtons(
    lines.join('\n'),
    [
      { id: 'owner_catalog_update', title: 'Update stock/price' },
      { id: 'owner_catalog_discount', title: 'Create discount' },
      { id: 'owner_catalog_import', title: 'Upload new sheet' },
    ],
  ) }];
}
if (row.result === 'already_applied') return [{ json: makeText('That bulk import was already applied earlier.') }];
return [{ json: makeText(String(row.message || 'I could not find that bulk import job. Please upload the file again.')) }];
